// --- RSI SAFETY FILTER ---
// Settings are now dynamic, but logic remains local for speed
const RSI_MAX = 70; 
const RSI_MIN = 30; 

const input = $input.first().json;
const rsi = parseFloat(input.rsi || input.RSI); 
const signal = input.signal; 

if (!rsi) return { json: input }; 

let isSafe = true;

// 1. Long Check
if (signal === 'LONG' && rsi > RSI_MAX) isSafe = false;

// 2. Short Check
if (signal === 'SHORT' && rsi < RSI_MIN) isSafe = false;

// --- RESULT ---
if (isSafe) {
    return { json: input };
} else {
    return []; // Stop execution
}

// 1. Get AI Output
const inputItem = $input.first();
const aiRaw = inputItem ? (inputItem.json.text || "{}") : "{}";

let marketData = {};
try {
    marketData = $('🧠 Analyze Logic').item.json;
} catch(e) {
    marketData = { symbol: "ERROR", price: 0 };
}

// 2. Clean JSON from Markdown
let aiReason = "CONFIRM: Analysis confirmed.";
let cleanAi = aiRaw.replace(/```json/g, '').replace(/```/g, '').trim();

const firstBrace = cleanAi.indexOf('{');
const lastBrace = cleanAi.lastIndexOf('}');

if (firstBrace !== -1 && lastBrace !== -1) {
    try {
        const parsed = JSON.parse(cleanAi.substring(firstBrace, lastBrace + 1));
        if (parsed.reason) {
            aiReason = parsed.reason;
        }
    } catch (e) {
        aiReason = "CHECK: " + cleanAi.substring(0, 200);
    }
} else if (cleanAi.length > 5) {
    aiReason = cleanAi.substring(0, 250);
}

return {
    json: {
        ...marketData,
        ai_reason: aiReason,
        processed_at: new Date().toISOString()
    }
};

const newsData = $input.first()?.json?.Data || [];
let newsText = "No recent news found.";
if (newsData.length > 0) {
    const headlines = newsData.slice(0, 3).map(n => `- ${n.title}`).join('\n');
    newsText = `Latest News:\n${headlines}`;
}
const techData = $('🧠 Analyze Logic').first().json;

return {
    json: {
        ...techData,
        news_context: newsText
    }
};

// --- STRATEGY SETTINGS ---
const MIN_VOL_X = 1.2; // Volume multiplier threshold
const DEDUP_TIMEOUT_MS = 60 * 60 * 1000; // 1 Hour cooldown per coin

const staticData = $getWorkflowStaticData('global');
if (!staticData.lastSignals) staticData.lastSignals = {};

const items = $input.all();
const klines = items.map(i => i.json);
let symbol = "UNKNOWN";
try { symbol = $('SplitInBatches').first().json.symbol; } catch(e) {}
const noSignal = () => ({ json: { hasSignal: false, symbol } });

// Need at least 200 candles for EMA calculation
if (klines.length < 200) return noSignal(); 

const closes = klines.map(k => parseFloat(k[4]));
const highs = klines.map(k => parseFloat(k[2]));
const lows = klines.map(k => parseFloat(k[3]));
const volumes = klines.map(k => parseFloat(k[5]));

const lastIdx = closes.length - 2; // Closed candle
const prevIdx = lastIdx - 1;     // Previous candle

const currentClose = closes[lastIdx];
const currentVol = volumes[lastIdx];

// --- 1. EMA 200 (Trend Filter) ---
function calculateEMA(data, period) {
    const k = 2 / (period + 1);
    let ema = data[0];
    for (let i = 1; i < data.length; i++) {
        ema = (data[i] * k) + (ema * (1 - k));
    }
    return ema;
}
const ema200 = calculateEMA(closes.slice(0, lastIdx + 1), 200);
const isUpTrend = currentClose > ema200;

// --- 2. BOLLINGER BANDS ---
const bbPeriod = 20;
const sliceBB = closes.slice(lastIdx - bbPeriod + 1, lastIdx + 1);
const smaBB = sliceBB.reduce((a, b) => a + b, 0) / bbPeriod;
const stdDev = Math.sqrt(sliceBB.map(x => Math.pow(x - smaBB, 2)).reduce((a, b) => a + b, 0) / bbPeriod);
const upperBand = smaBB + (stdDev * 2);
const lowerBand = smaBB - (stdDev * 2);
const bbWidth = ((upperBand - lowerBand) / smaBB * 100).toFixed(2);

// --- 3. RSI (14) ---
function getRSI(data, endIdx) {
    let gains = 0, losses = 0;
    const period = 14;
    for (let i = endIdx - period; i < endIdx; i++) {
        let diff = data[i+1] - data[i];
        if (diff >= 0) gains += diff;
        else losses -= diff;
    }
    let rs = (losses === 0) ? 100 : gains / losses;
    return 100 - (100 / (1 + rs));
}
const rsi = getRSI(closes, lastIdx);
const prevRsi = getRSI(closes, prevIdx);

let rsiStatus = rsi < 35 ? "Oversold" : (rsi > 65 ? "Overbought" : "Neutral");

// --- 4. VOLUME ANALYSIS ---
const avgVol = volumes.slice(lastIdx - 20, lastIdx).reduce((a, b) => a + b, 0) / 20;
const volFactor = currentVol / avgVol;

// --- 5. ENTRY LOGIC ---
let signal = null;

// LONG Logic
if (isUpTrend && currentClose < lowerBand && rsi > prevRsi && rsi < 45 && volFactor > MIN_VOL_X) {
    signal = "Long";
} 
// SHORT Logic
else if (!isUpTrend && currentClose > upperBand && rsi < prevRsi && rsi > 55 && volFactor > MIN_VOL_X) {
    signal = "Short";
}

if (!signal) return noSignal();

// --- 6. RISK/REWARD CALC ---
let tpMultiplier = 2.5; 
if (parseFloat(bbWidth) > 3 || volFactor > 2.0) {
    tpMultiplier = 3.5; // Target higher for volatile assets
}

// --- 7. ATR & SL/TP ---
let trSum = 0;
for (let i = lastIdx - 14; i <= lastIdx; i++) {
    trSum += Math.max(highs[i]-lows[i], Math.abs(highs[i]-(closes[i-1]||0)), Math.abs(lows[i]-(closes[i-1]||0)));
}
const atr = trSum / 14;
const prec = currentClose > 10 ? 2 : 5;

// Deduplication check
const now = Date.now();
if (now - (staticData.lastSignals[symbol] || 0) < DEDUP_TIMEOUT_MS) return noSignal();
staticData.lastSignals[symbol] = now;

return {
    json: {
        hasSignal: true,
        symbol,
        price: currentClose,
        signal,
        emoji: signal === "Long" ? "🟢" : "🔴",
        rsi: rsi.toFixed(1),
        rsi_status: rsiStatus,
        vol_x: volFactor.toFixed(1),
        bb_width: bbWidth,
        trend: isUpTrend ? "Bullish 📈" : "Bearish 📉",
        rr_ratio: `1:${tpMultiplier}`,
        calc_sl: (signal === "Long" ? currentClose - atr * 1.5 : currentClose + atr * 1.5).toFixed(prec),
        calc_tp: (signal === "Long" ? currentClose + atr * tpMultiplier : currentClose - atr * tpMultiplier).toFixed(prec)
    }
};

// --- CONFIGURATION LOAD ---
// We get the blacklist string from the new Config Node
const rawBlacklist = $('📝 MAIN CONFIG').first().json.BLACKLIST || "";
const BLACKLIST = rawBlacklist.split(',').map(s => s.trim());

// 1. Filter USDT Pairs only
let pairs = $input.all().map(i => i.json).filter(i => i.symbol.endsWith('USDT'));

// 2. Sort by Quote Volume (High liquidity first)
pairs.sort((a, b) => parseFloat(b.quoteVolume) - parseFloat(a.quoteVolume));

// 3. Remove Blacklisted symbols
pairs = pairs.filter(p => !BLACKLIST.includes(p.symbol));

// 4. Select TOP Candidates (e.g., Rank 10 to 150 to avoid stablecoins usually at top)
return pairs.slice(10, 150).map(c => ({ json: { symbol: c.symbol } }));

// --- CONFIGURATION LOAD ---
const config = $('📝 MAIN CONFIG').first().json;

const API_KEY = config.BINANCE_API_KEY;
const USDT_AMOUNT = parseFloat(config.TRADE_AMOUNT_USDT);
const LEVERAGE = parseInt(config.LEVERAGE);
const TRAILING_CALLBACK = 2.0;

// --- LOGIC BELOW ---
const marketData = $('🛠️ Merge & Clean Data').item.json;
const symbol = marketData.symbol;

const allExchangeRules = $input.first().json;
const symbolInfo = allExchangeRules.symbols.find(s => s.symbol === symbol);

if (!symbolInfo) {
    throw new Error(`Symbol ${symbol} not found on Binance.`);
}

// Precision Calc
const priceFilter = symbolInfo.filters.find(f => f.filterType === 'PRICE_FILTER');
const lotFilter = symbolInfo.filters.find(f => f.filterType === 'LOT_SIZE');

const getPrecision = (step) => {
    const s = parseFloat(step).toString();
    return s.includes('.') ? s.split('.')[1].length : 0;
};

const pPrec = getPrecision(priceFilter.tickSize);
const qPrec = getPrecision(lotFilter.stepSize);

const toB = (val, prec) => {
    if (!val || isNaN(val)) return "0";
    const factor = Math.pow(10, prec);
    const rounded = Math.floor(parseFloat(val) * factor) / factor;
    return rounded.toFixed(prec).replace(/\.?0+$/, "");
};

// Prices
const currentPrice = parseFloat(marketData.price);
let sl = parseFloat(marketData.calc_sl);
let tp = parseFloat(marketData.calc_tp);

if (!sl || sl === 0) sl = marketData.signal === 'LONG' ? currentPrice * 0.98 : currentPrice * 1.02;
if (!tp || tp === 0) tp = marketData.signal === 'LONG' ? currentPrice * 1.04 : currentPrice * 0.96;

const slPrice = toB(sl, pPrec);
const tpPrice = toB(tp, pPrec);
const totalQty = toB((USDT_AMOUNT * LEVERAGE) / currentPrice, qPrec);

if (parseFloat(totalQty) <= 0) return []; 

const side = marketData.signal === 'LONG' ? 'BUY' : 'SELL';
const closeSide = marketData.signal === 'LONG' ? 'SELL' : 'BUY';
const timestamp = Date.now();

function makeQuery(p) { return Object.keys(p).map(k => `${k}=${p[k]}`).join('&'); }

// Order Construction
return [
    { json: { queryString: makeQuery({symbol, marginType: 'ISOLATED', timestamp}), endpoint: "/fapi/v1/marginType", apiKey: API_KEY, type: "MARGIN" } },
    { json: { queryString: makeQuery({symbol, leverage: LEVERAGE, timestamp}), endpoint: "/fapi/v1/leverage", apiKey: API_KEY, type: "LEVERAGE" } },
    { json: { queryString: makeQuery({symbol, side, type: 'MARKET', quantity: totalQty, timestamp}), endpoint: "/fapi/v1/order", apiKey: API_KEY, type: "ENTRY" } },
    { json: { queryString: makeQuery({symbol, side: closeSide, type: 'STOP_MARKET', stopPrice: slPrice, closePosition: 'true', timestamp}), endpoint: "/fapi/v1/order", apiKey: API_KEY, type: "SL" } },
    { json: { queryString: makeQuery({symbol, side: closeSide, type: 'TAKE_PROFIT_MARKET', stopPrice: tpPrice, quantity: toB(parseFloat(totalQty)/2, qPrec), reduceOnly: 'true', timestamp}), endpoint: "/fapi/v1/order", apiKey: API_KEY, type: "TP" } },
    { json: { queryString: makeQuery({symbol, side: closeSide, type: 'TRAILING_STOP_MARKET', quantity: toB(parseFloat(totalQty)/2, qPrec), callbackRate: TRAILING_CALLBACK, activationPrice: tpPrice, reduceOnly: 'true', timestamp}), endpoint: "/fapi/v1/order", apiKey: API_KEY, type: "TRAILING" } }
];
